export default function ProgressBar({ current = 1, total = 1 }) {
  const percent = Math.round((current / total) * 100);

  return (
    <div className="mb-8">
      <div className="h-1.5 w-full rounded-full bg-slate-800">
        <div
          className="h-1.5 rounded-full bg-indigo-500 shadow-[0_0_10px_rgba(99,102,241,0.5)] transition-all duration-500 ease-out"
          style={{ width: `${percent}%` }}
        />
      </div>
    </div>
  );
}
